INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "たまには\n協力するのもいいんじゃない？\nあたしも手を貸してあげる", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106001, "2015/12/17 15:00:00", 1, 7, "キャル", 7001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "多くの方と協力して\n戦えるようです\n主さまなら、さぞ\nご活躍なさることでしょう", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105901, "2015/12/17 15:00:00", 1, 7, "コッコロ", 7002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "たくさんの人と一緒に\n協力バトルです！\nがんばりましょう☆", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105801, "2015/12/17 15:00:00", 1, 7, "ペコリーヌ", 7003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "ジュエルを食べ物…\nいえ、貴重品と交換できます！", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105801, "2015/12/17 15:00:00", 1, 10, "ペコリーヌ", 10001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "ジュエルはよく考えて\n使うことね\n無駄遣い厳禁！", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106001, "2015/12/17 15:00:00", 1, 10, "キャル", 10002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "主さまのジュエルで\n貴重な品々を購入できます\nですが、無駄遣いは\n『めっ』でございますよ", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105901, "2015/12/17 15:00:00", 1, 10, "コッコロ", 10003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 2104010, 0, 0.0, "ジュエルがあれば\n貴重品と交換できるみたい\n大事に使いましょうね", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106401, "2015/12/17 15:00:00", 2, 10, "シェフィ", 10004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "特定の条件を達成すると\n報酬がもらえますよ！\nがんばりましょう♪　", 0.0, 1, "2030/12/17 14:59:59", -416.5, 105801, "2015/12/17 15:00:00", 1, 12, "ペコリーヌ", 12001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "思い出が詰まってるって\nいろいろあったけど\n振り返るのもいいんじゃない？", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106001, "2015/12/17 15:00:00", 1, 13, "キャル", 13001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "主さまとの楽しい日々…\nこちらで何度でも\n思い返しましょう♪", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105901, "2015/12/17 15:00:00", 1, 13, "コッコロ", 13002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 2104010, 0, 0.0, "みんなとの大切な思い出が\nたくさん詰まってるのね\n一緒に振り返って、\n心に刻みたいわ", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106401, "2015/12/17 15:00:00", 2, 13, "シェフィ", 13003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "女の子との思い出が\nたくさん見られますよ！\nヒューヒュー♪\nモテモテですねー☆", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105801, "2015/12/17 15:00:00", 1, 13, "ペコリーヌ", 13004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "育成に必要なアイテムが\n獲得できるクエストです\nわたくし、主さまのために、\n強くなりますよ", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105901, "2015/12/17 15:00:00", 1, 14, "コッコロ", 14001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 2104010, 0, 0.0, "このクエストを攻略すると、\nアイテムが手に入るらしいわ。\nもっと強くなるために、\n一生懸命がんばるわね！", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106401, "2015/12/17 15:00:00", 2, 14, "シェフィ", 14002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "このクエストを攻略すれば、\nアイテムがもらえますよ\nたくさん集めて、どんどん\n強くなっちゃいましょう！", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105801, "2015/12/17 15:00:00", 1, 14, "ペコリーヌ", 14003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "クエストを攻略すると、\nアイテムが手に入るんだって\nもらえるものは、\nもらっておきましょ！", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106001, "2015/12/17 15:00:00", 1, 14, "キャル", 14004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "主さま、旅の準備を整えて\nより充実した冒険をいたし\nましょう", 0.0, 1, "2030/12/17 14:59:59", -470.0, 105901, "2015/12/17 15:00:00", 1, 15, "コッコロ", 15001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 2104010, 0, 0.0, "ねぇ…クランに加入してみない？\n一人も楽しいけど、みんなと\n一緒も賑やかでいいと思うの", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106401, "2015/12/17 15:00:00", 2, 16, "シェフィ", 16001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "クランに加入してみませんか？\nみんなといっしょに冒険した方が、\n楽しいですよ！", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105801, "2015/12/17 15:00:00", 1, 16, "ペコリーヌ", 16002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "クランに入れるらしいわよ\nせっかくだから入ってみたら？\nけっこう楽しいみたいよ♪", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106001, "2015/12/17 15:00:00", 1, 16, "キャル", 16003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "こちらでクランに加入できます\n素敵なクランがたくさんあって、\n目移りしてしまいますね", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105901, "2015/12/17 15:00:00", 1, 16, "コッコロ", 16004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, " こちらではクランバトルに\n 参加された仲間のみなさんの\n 活躍を振り返ることができます", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105901, "2015/12/17 15:00:00", 1, 17, "コッコロ", 17002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "模擬戦の戦績もアンタが\n気に入ったものがあれば\n記録しておけるのね", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106001, "2015/12/17 15:00:00", 1, 25, "キャル", 17004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "主さま、今回のクランバトルでの\nご活躍が記録されています\nバトルの参考にいたしましょう", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105901, "2015/12/17 15:00:00", 1, 25, "コッコロ", 17005);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 2104010, 0, 0.0, "今回のクランバトルの調子は\nどうかしら？\n戦績を見れば、次のバトルに\n活かせるかもしれないわ", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106401, "2015/12/17 15:00:00", 2, 25, "シェフィ", 17006);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "今回のクランバトルでの戦績を\nおさらいできますよ！\n私にも見せてください☆", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105801, "2015/12/17 15:00:00", 1, 25, "ペコリーヌ", 17007);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "ようこそ！\nこちらでは、\nギルドハウスで流れる音楽の\n変更や購入が出来ますよ", 0.0, 1, "2030/12/17 14:59:59", -363.0, 190801, "2015/12/17 15:00:00", 1, 18, "カリン", 18001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 0, 0, 0.0, "ＢＧＭの変更や購入は、こちらから\nできますよ\n素敵な音楽を、たくさんご用意\nいたしました！", 0.0, 1, "2030/12/17 14:59:59", -363.0, 190801, "2015/12/17 15:00:00", 1, 18, "カリン", 18002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (3, 0, 0, 0.0, "ギルドハウスの\nＢＧＭを変更できますよ\nあなたの好きな曲、\n私にも聴かせてくださいね", 0.0, 1, "2030/12/17 14:59:59", -470.0, 190801, "2015/12/17 15:00:00", 1, 19, "カリン", 19001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (4, 0, 0, 0.0, "こちらでは、ＢＧＭの変更が\nできますよ\nどんな曲に変更しますか？\nふふふ、私も楽しみです♪", 0.0, 1, "2030/12/17 14:59:59", -470.0, 190801, "2015/12/17 15:00:00", 1, 19, "カリン", 19002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (5, 0, 0, 0.0, "こちらでは、ＢＧＭを購入\nすることができますよ\n試聴することもできるので、\nじっくり選んでくださいね", 0.0, 1, "2030/12/17 14:59:59", -470.0, 190801, "2015/12/17 15:00:00", 1, 20, "カリン", 20001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (6, 0, 0, 0.0, "いらっしゃいませ！\nＢＧＭの購入はこちらです\n素敵な曲がたくさんあって、\n目移りしちゃいますね", 0.0, 1, "2030/12/17 14:59:59", -470.0, 190801, "2015/12/17 15:00:00", 1, 20, "カリン", 20002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "ここで手に入れたアイテムで\n専用装備を作成できるみたいね\nアイテムが集まったら\nさっそく作ってみましょ！", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106001, "2015/12/17 15:00:00", 1, 21, "キャル", 21001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "攻略すると珍しいアイテムが\n手に入りますよ\nこのアイテムで専用装備を\n作成できるようです", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105901, "2015/12/17 15:00:00", 1, 21, "コッコロ", 21002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 2104010, 0, 0.0, "専用装備が欲しいなら\nこのクエストに挑戦するといいわ\n集めた素材でもっともっと\n強くなりましょう", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106401, "2015/12/17 15:00:00", 2, 21, "シェフィ", 21003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "専用装備の作成に必要な\nアイテムを獲得できますよ\nたくさん集めてどんどん\n強くなりましょう！", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105801, "2015/12/17 15:00:00", 1, 21, "ペコリーヌ", 21004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "投票はこちらです\nあなたが応援したい女の子に\n思いを込めた一票を\nお願いします！", 0.0, 1, "2030/12/17 14:59:59", -430.0, 190801, "2015/12/17 15:00:00", 1, 22, "カリン", 22001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 0, 0, 0.0, "ようこそ！\nあなたが思いを寄せるのは\nどの女の子ですか？\n応援してあげてくださいね！", 0.0, 1, "2030/12/17 14:59:59", -430.0, 190801, "2015/12/17 15:00:00", 1, 22, "カリン", 22002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (3, 0, 0, 0.0, "たくさんの投票、\nありがとうございました\n結果発表を楽しみに\n待っていてくださいね！", 0.0, 1, "2030/12/17 14:59:59", -430.0, 190801, "2015/12/17 15:00:00", 1, 23, "カリン", 23001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (4, 0, 0, 0.0, "ただ今、人気投票の\n集計中です\n結果が出るまでもう少しだけ\nお待ちくださいね", 0.0, 1, "2030/12/17 14:59:59", -430.0, 190801, "2015/12/17 15:00:00", 1, 23, "カリン", 23002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 10011, 4.08, "あなた様が手伝ってくださった\nチョコレートケーキ\n美味しくないはずがありませんわ", 8.0, 2, "2030/12/17 14:59:59", -385.0, 109001, "2019/01/31 12:00:00", 1, 24, "エリコ（バレンタイン）", 24001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 0, 10011, 5.0, "このような失敗、あなた様が\nするはずありません\nもう一度挑戦してみましょう", 8.0, 2, "2030/12/17 14:59:59", -385.0, 109001, "2019/01/31 12:00:00", 1, 24, "エリコ（バレンタイン）", 24002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (3, 0, 10011, 10.11, "あなた様のために\n作っているケーキを\nあなた様に手伝っていただく……\nことになるなんて……クスクス", 8.0, 2, "2030/12/17 14:59:59", -385.0, 109001, "2019/01/31 12:00:00", 1, 24, "エリコ（バレンタイン）", 24003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (4, 0, 10011, 4.0, "あまり気に病む必要はありませんわ\nこれからは私がたっぷりと\n時間をかけて教えて差し上げますから", 8.0, 2, "2030/12/17 14:59:59", -385.0, 109001, "2019/01/31 12:00:00", 1, 24, "エリコ（バレンタイン）", 24004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (5, 0, 10011, 6.0, "今回は調子が悪かった……のですか？\nあなた様が手伝ってくれたものなら\nわたしはどんなものでも……クスクス", 8.0, 2, "2030/12/17 14:59:59", -385.0, 109001, "2019/01/31 12:00:00", 1, 24, "エリコ（バレンタイン）", 24005);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (6, 0, 10011, 0.0, "あなた様が手がけた\nチョコレートケーキは\n私にとっての宝物……\n侮辱する者は生かしておきませんわ", 0.0, 1, "2030/12/17 14:59:59", 0.0, 109002, "2019/01/31 12:00:00", 1, 24, "エリコ（バレンタイン）", 24006);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (7, 0, 10011, 0.0, "とても素晴らしい出来栄えですわ！\nあなた様にふさわしい\nチョコレートケーキができました", 0.0, 1, "2030/12/17 14:59:59", 0.0, 109002, "2019/01/31 12:00:00", 1, 24, "エリコ（バレンタイン）", 24007);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (8, 0, 10011, 0.0, "私を手伝ってくれたあなた様は\nすでに私の虜……\n甘い世界に誘って差し上げますわ", 0.0, 1, "2030/12/17 14:59:59", 0.0, 109002, "2019/01/31 12:00:00", 1, 24, "エリコ（バレンタイン）", 24008);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (9, 0, 10011, 0.0, "あなた様の愛情\nしかと受け止めました\nこれが……私たちの初めての\n共同作業ですわね……クスクス", 0.0, 1, "2030/12/17 14:59:59", 0.0, 109002, "2019/01/31 12:00:00", 1, 24, "エリコ（バレンタイン）", 24009);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10, 0, 10011, 0.0, "これは世界一の\nチョコレートケーキですわ\nだって、あなた様が腕によりをかけて\n作ってくださったんですもの", 0.0, 1, "2030/12/17 14:59:59", 0.0, 109002, "2019/01/31 12:00:00", 1, 24, "エリコ（バレンタイン）", 24010);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 10011, 2.12, "上手にできなくて残念だった？\nでも、弟くんの気持ちが嬉しいな\nいつだってお姉ちゃんは\nそばにいるからね♪", 8.0, 2, "2030/12/17 14:59:59", -385.0, 109101, "2019/01/31 12:00:00", 1, 24, "シズル（バレンタイン）", 24011);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 0, 10011, 4.19, "うーん、弟くんには珍しく\n緊張しちゃったのかな？\nもう一度チャレンジしてみる？", 8.0, 2, "2030/12/17 14:59:59", -385.0, 109101, "2019/01/31 12:00:00", 5, 24, "シズル（バレンタイン）", 24012);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (3, 0, 10011, 2.3, "お姉ちゃんのお手伝い、\nよくできました！\nあー、\nまだつまみ食いしちゃダメだぞ！", 8.0, 4, "2030/12/17 14:59:59", -385.0, 109101, "2019/01/31 12:00:00", 2, 24, "シズル（バレンタイン）", 24013);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (4, 0, 10011, 0.0, "見てみて！\nスポンジに綺麗な焼き目がついてるよ\nさっすが弟くんだね！", 0.0, 1, "2030/12/17 14:59:59", 0.0, 109102, "2019/01/31 12:00:00", 1, 24, "シズル（バレンタイン）", 24014);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (5, 0, 10011, 5.23, "まぁまぁ、落ち込まないで\n見た目は……個性的だけど、\n味は絶対美味しいはずだから！", 8.0, 2, "2030/12/17 14:59:59", -385.0, 109101, "2019/01/31 12:00:00", 5, 24, "シズル（バレンタイン）", 24015);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (6, 0, 10011, 0.0, "弟くんみたいな\n可愛いケーキができたよ！\n早く食べてみたいでしょ♪", 0.0, 1, "2030/12/17 14:59:59", 0.0, 109102, "2019/01/31 12:00:00", 1, 24, "シズル（バレンタイン）", 24016);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (7, 0, 10011, 5.01, "あれれ？　弟くん、指に\nチョコレートがくっついてるよ？\nお姉ちゃんが舐めてあげるね、\nはぁむ！", 8.0, 2, "2030/12/17 14:59:59", -385.0, 109101, "2019/01/31 12:00:00", 1, 24, "シズル（バレンタイン）", 24017);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (8, 0, 10011, 0.0, "なかなか上手にできたんじゃない？\nでも弟くんはまだまだできる子！\nお姉ちゃん、信じてるからね", 0.0, 1, "2030/12/17 14:59:59", 0.0, 109102, "2019/01/31 12:00:00", 1, 24, "シズル（バレンタイン）", 24018);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (9, 0, 10011, 0.0, "わぁ～、\nとっても美味しそうにできたね！\n弟くん手慣れてたから\nお姉ちゃん安心して任せられちゃった！", 0.0, 1, "2030/12/17 14:59:59", 0.0, 109102, "2019/01/31 12:00:00", 1, 24, "シズル（バレンタイン）", 24019);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10, 0, 10011, 0.0, "や～ん、弟くんが手伝ってくれた\nチョコレートケーキ！\nすっごく美味しそうにできたね♪", 0.0, 1, "2030/12/17 14:59:59", 0.0, 109102, "2019/01/31 12:00:00", 1, 24, "シズル（バレンタイン）", 24020);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 2104010, 0, 0.0, "ここから先は神聖な場所みたい\nどんなお宝が眠っているのか、\n今から探索するのが楽しみね♪", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106401, "2015/12/17 15:00:00", 2, 26, "シェフィ", 26001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "ここから先は神聖な場所\nみたいです！\nどんなお宝が手に入るか\n楽しみですね！", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105801, "2015/12/17 15:00:00", 1, 26, "ペコリーヌ", 26002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "この先は神聖な場所みたい。\n手に入るお宝も並じゃないけど\n気を付けていかないと\n痛い目にあうわよ", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106001, "2015/12/17 15:00:00", 1, 26, "キャル", 26003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "ここから先は神聖な場所\nでございます。\n気を引き締めてお宝の\n調査探索に参りましょう", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105901, "2015/12/17 15:00:00", 1, 26, "コッコロ", 26004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 2104010, 0, 0.0, "ここにさらなる力を得るための\nアイテムが眠っている…って\nみんな言ってるわ。ふふっ、\nそれじゃあ挑戦してみましょうか", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106401, "2015/12/17 15:00:00", 2, 27, "シェフィ", 27001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "ここにさらなる力を得るための\nアイテムが眠っているみたい\nです！　どこから挑戦するか\n迷っちゃいますね！", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105801, "2015/12/17 15:00:00", 1, 27, "ペコリーヌ", 27002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "ここにさらなる力を得るための\nアイテムが眠っているみたい！\nどんどん挑戦して\n強くなっちゃいましょ！", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106001, "2015/12/17 15:00:00", 1, 27, "キャル", 27003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "こちらにさらなる力を得る\nためのアイテムが眠っている\nようです。主さま、どこから\n挑戦いたしましょう。", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105901, "2015/12/17 15:00:00", 1, 27, "コッコロ", 27004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "ようこそ！\n皆さんの素敵な出会いを\nギルド管理協会が\nお手伝いします！", 0.0, 1, "2030/12/17 14:59:59", -363.0, 190801, "2019/09/24 15:00:00", 1, 28, "カリン", 28001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 0, 0, 0.0, "ギルド管理協会です\nフレンドに関しては\nこちらでご確認ください", 0.0, 1, "2030/12/17 14:59:59", -363.0, 190801, "2019/09/24 15:00:00", 1, 28, "カリン", 28002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (3, 0, 0, 0.0, "こちらがフレンドの\n皆さんです\n素敵な関係を\n築いてくださいね！", 0.0, 1, "2030/12/17 14:59:59", -409.0, 190801, "2019/09/24 15:00:00", 1, 29, "カリン", 29001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (4, 0, 0, 0.0, "こちらの一覧で\nフレンドのプロフィールを\n確認できますよ", 0.0, 1, "2030/12/17 14:59:59", -409.0, 190801, "2019/09/24 15:00:00", 1, 29, "カリン", 29002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (5, 0, 0, 0.0, "フレンド管理は\nこちらになります\n新しいフレンドとの出会いを\n楽しんでくださいね！", 0.0, 1, "2030/12/17 14:59:59", -409.0, 190801, "2019/09/24 15:00:00", 1, 30, "カリン", 30001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (6, 0, 0, 0.0, "フレンドの申請や\n承認ができますよ\nどうぞ、良き交流を！", 0.0, 1, "2030/12/17 14:59:59", -409.0, 190801, "2019/09/24 15:00:00", 1, 30, "カリン", 30002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (7, 0, 0, 0.0, "バトルをして力比べを\nしてみましょう！\n実力が試されますね、\n頑張ってください！", 0.0, 1, "2030/12/17 14:59:59", -409.0, 190801, "2019/10/31 12:00:00", 1, 31, "カリン", 31001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (8, 0, 0, 0.0, "気になるパーティと\nバトルをしてみましょう！\nどちらが勝利するのか、\n私も楽しみにしていますね", 0.0, 1, "2030/12/17 14:59:59", -409.0, 190801, "2019/10/31 12:00:00", 1, 31, "カリン", 31002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "ルーキーの皆さんのために\n特別なミッションを\nご用意いたしました！\nぜひ、挑戦してください！", 0.0, 1, "2020/01/04 4:59:59", -409.0, 190801, "2019/12/20 5:00:00", 1, 32, "カリン", 32001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 0, 0, 0.0, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", 0.0, 1, "2020/01/04 4:59:59", -409.0, 190801, "2019/12/20 5:00:00", 1, 32, "カリン", 32002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (3, 0, 0, 0.0, "フレンドになって\n初心者の方を応援しましょう！\n素敵な報酬が待っていますよ！", 0.0, 1, "2020/01/04 4:59:59", -409.0, 190801, "2019/12/20 5:00:00", 1, 33, "カリン", 33001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (4, 0, 0, 0.0, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", 0.0, 1, "2020/01/04 4:59:59", -409.0, 190801, "2019/12/20 5:00:00", 1, 33, "カリン", 33002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (5, 0, 0, 0.0, "お疲れ様でした！\nミッションの報酬の受け取りは\nこちらからできますよ！", 0.0, 1, "2020/01/10 11:59:59", -409.0, 190801, "2020/01/04 5:00:00", 1, 34, "カリン", 34001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (6, 0, 0, 0.0, "ミッション報酬の受け取りは\nこちら！\n受け取り漏れの無いように\n気を付けてくださいね！", 0.0, 1, "2020/01/10 11:59:59", -409.0, 190801, "2020/01/04 5:00:00", 1, 34, "カリン", 34002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 5.3, "過去のストーリーイベントを\n楽しめちゃいますよ！\n遊んだことのないものがあれば\n一緒にやってみましょう♪", 0.0, 2, "2030/12/17 14:59:59", -458.0, 105801, "2015/12/17 15:00:00", 1, 38, "ペコリーヌ", 38001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 0, 0, 6.5, "これまでのイベントで登場した\n限定キャラを仲間にできたり\nメモリーピースが手に入る\nみたいですよ。やばいですね☆", 0.0, 2, "2030/12/17 14:59:59", -458.0, 105801, "2015/12/17 15:00:00", 1, 38, "ペコリーヌ", 38002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 0, 0, 0.0, "", 9999.0, 3, "2020/04/08 23:59:59", 9999.0, 105801, "2020/04/01", 3, 39, "ペコリーヌ", 39005);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 0, 0, 0.0, "これまでに出題された\n問題を振り返ることが\nできますよ\n復習は大切です♪", 0.0, 1, "2030/12/17 14:59:59", -430.0, 190801, "2015/12/17 15:00:00", 1, 40, "カリン", 40001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 2104010, 0, 0.0, "ここでは腕試しが\nできるんですって。\n自分の実力を測るのに、\nちょうどよさそうね。", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106401, "2015/12/17 15:00:00", 1, 41, "シェフィ", 41001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "ここで腕試しを\nしていきましょう！\n全力全開、\nがんばっちゃいますよ～！", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105801, "2015/12/17 15:00:00", 1, 41, "ペコリーヌ", 41002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "ここで腕試しが\nできるみたいね。\n試してみるのも\nいいんじゃない？", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106001, "2015/12/17 15:00:00", 1, 41, "キャル", 41003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "腕試しができるようです。\nここで練習を重ね、実戦に\n活かしてまいりましょう。", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105901, "2015/12/17 15:00:00", 1, 41, "コッコロ", 41004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "訓練の成果に応じて、\n報酬がもらえるそうです。\n共に励んでいきましょう。", 0.0, 1, "2030/12/17 14:59:59", -416.5, 105901, "2015/12/17 15:00:00", 1, 42, "コッコロ", 42001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 2104010, 0, 0.0, "目標を達成すれば、\n報酬がもらえるみたい。\n頑張り甲斐があるわね。", 0.0, 1, "2030/12/17 14:59:59", -416.5, 106401, "2015/12/17 15:00:00", 1, 42, "シェフィ", 42002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "腕試しをがんばれば、\n報酬がもらえますよ。\n挑戦していきましょう☆", 0.0, 1, "2030/12/17 14:59:59", -416.5, 105801, "2015/12/17 15:00:00", 1, 42, "ペコリーヌ", 42003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "ミッションを達成すると、\n報酬が出るんですって。\n一緒にやってみましょ！", 0.0, 1, "2030/12/17 14:59:59", -416.5, 106001, "2015/12/17 15:00:00", 1, 42, "キャル", 42004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "ここからアリーナに\n挑戦できますよ！\n編成を工夫してライバルに\n挑んじゃいましょう！", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105801, "2015/12/17 15:00:00", 1, 43, "ペコリーヌ", 43001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "こちらからアリーナに\n挑戦することができます。\n主さまらしい編成で\nライバルに挑みましょう。", 0.0, 1, "2030/12/17 14:59:59", -363.0, 105901, "2015/12/17 15:00:00", 1, 43, "コッコロ", 43002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "ここからアリーナに\n挑戦できるわよ！\nしっかり編成を考えて\nライバルに挑みなさい！", 0.0, 1, "2030/12/17 14:59:59", -363.0, 106001, "2015/12/17 15:00:00", 1, 43, "キャル", 43003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "ミッションをクリアすると報酬が\n受け取れるわ。ジャンジャン\nクリアしてバリバリ強化して\nあげなさい♪", 0.0, 1, "2030/12/17 14:59:59", -416.5, 123001, "2015/12/17 15:00:00", 1, 44, "アメス", 43004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 0, 0, 0.0, "ぼんやりしてる場合じゃないわ。\n早くミッションをクリアして\n報酬を受け取ってきなさい！", 0.0, 1, "2030/12/17 14:59:59", -416.5, 123001, "2015/12/17 15:00:00", 1, 44, "アメス", 43005);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (3, 0, 0, 5.79, "ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", 0.0, 2, "2030/12/17 14:59:59", -416.5, 123001, "2015/12/17 15:00:00", 1, 45, "アメス", 43006);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "はい、お疲れさま。\nここではマスタリーチケットを\n使って、マスタリー強化素材を\n手に入れることができるわよ。", 0.0, 1, "2030/12/17 14:59:59", -371.5, 123001, "2015/12/17 15:00:00", 1, 46, "アメス", 46001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 0.0, "呼ばれて飛び出てお姉ちゃんだよ♪\nたとえ火の中、水の中、迷宮の中っ\nこのダンジョンを踏破できるよう\n弟くんを応援してあげるからねっ♪", 0.0, 2, "2030/12/17 14:59:59", -416.5, 104901, "2015/12/17 15:00:00", 2, 47, "シズル", 47001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0, 0, 9.32, "ほんとーに不思議な場所ですね～\nお兄ちゃんが冒険を頑張れるよう\nおまじないをかけてあげますねっ\nフレーフレー、お・兄・ちゃんっ♪", 0.0, 2, "2030/12/17 14:59:59", -416.5, 101101, "2015/12/17 15:00:00", 1, 47, "リノ", 47002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 0, 0, 0.0, "", 0.0, 2, "2030/12/17 14:59:59", -470.0, 104901, "2015/12/17 15:00:00", 2, 48, "シズル", 48001);
